queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?tool_name ?category WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTools ?child ; p:hasFinance_Apps ?parent . } GROUP BY ?child }
  ?child p:tool_name ?tool_name .
  ?child p:category ?category .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Finance_Apps } }
  FILTER(?nf = ?total)
}

